import { Component, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { Product } from '../../core/models';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-product-form',
  standalone: true,
  imports: [CommonModule, RouterLink, ReactiveFormsModule],
  templateUrl: './product-form.component.html',
})
export class ProductFormComponent {
  private auth = inject(AuthService);
  private fb = inject(FormBuilder);

  isAdmin = this.auth.hasRole('admin');

  id = inject(ActivatedRoute).snapshot.paramMap.get('id');

  products = signal<Product[]>([
    { id: 'p1', sku: 'STL-001', name: 'Steel Bolt M8', cost: 0.45, price: 1.2, onHand: 1200 },
    { id: 'p2', sku: 'STL-002', name: 'Steel Nut M8', cost: 0.3, price: 0.9, onHand: 1500 },
    { id: 'p3', sku: 'PIP-050', name: 'PVC Pipe 50mm', cost: 3.2, price: 7.5, onHand: 340 },
    { id: 'p4', sku: 'PIP-075', name: 'PVC Pipe 75mm', cost: 4.8, price: 10.9, onHand: 210 },
    { id: 'p5', sku: 'WIR-014', name: 'Copper Wire 14AWG', cost: 12.0, price: 24.0, onHand: 85 },
    { id: 'p6', sku: 'WIR-012', name: 'Copper Wire 12AWG', cost: 15.5, price: 30.0, onHand: 60 },
    { id: 'p7', sku: 'PNL-100', name: 'Control Panel', cost: 145.0, price: 320.0, onHand: 18 },
    { id: 'p8', sku: 'SEN-200', name: 'Proximity Sensor', cost: 22.5, price: 49.0, onHand: 140 },
    { id: 'p9', sku: 'VLV-030', name: 'Ball Valve 30mm', cost: 9.75, price: 21.0, onHand: 0 },
    { id: 'p10', sku: 'GSK-008', name: 'Rubber Gasket', cost: 0.85, price: 2.4, onHand: 4 },
  ]);

  product = computed(() => this.products().find((p) => p.id === this.id) ?? this.products()[0]);

  form = this.fb.group({
    sku: [this.product().sku, Validators.required],
    name: [this.product().name, Validators.required],
    cost: [this.product().cost, [Validators.required, Validators.min(0)]],
    price: [this.product().price, [Validators.required, Validators.min(0)]],
    onHand: [this.product().onHand, [Validators.required, Validators.min(0)]],
  });

  constructor() {
    if (!this.isAdmin) {
      this.form.disable();
    }
  }

  save(): void {
    if (!this.isAdmin || this.form.invalid) return;
    // Mockup: persistence is added by the service_agent stage.
  }
}
